const item = $input.item.json;

const companyName = $('loopOverItems').item.json['Company Name'] || "Unknown";

let newsItems = [];

if (item.rss && item.rss.channel && item.rss.channel.item) {
  newsItems = item.rss.channel.item;
  if (!Array.isArray(newsItems)) {
    newsItems = [newsItems];
  }
}

if (newsItems.length === 0) {
  return [{
    json: {
      error: true,
      status: "failed",
      data: "No news found.",
      "Company Name": companyName
    }
  }];
}

const cleanText = (text) => {
  if (!text) return "";
  return String(text).replace(/<[^>]*>/g, "").trim();
};

const topNews = newsItems.slice(0, 5);

const mergedNewsText = topNews.map((newsItem, index) => {
  return `Article ${index + 1}:
Title: ${cleanText(newsItem.title)}
Description: ${cleanText(newsItem.description)}
Date: ${newsItem.pubDate?._ || newsItem.pubDate || "Unknown"}`;
}).join('\n\n---\n\n');

return [{
  json: {
    error: false,
    status: "success",
    data: mergedNewsText,
    "Company Name": companyName
  }
}];

const rawText = $json.output;

if (!rawText || rawText.trim() === "") {
  return { json: buildErrorResult() };
}

let aiData;
try {
  let jsonData = JSON.parse(rawText);
  if (Array.isArray(jsonData)) {
    aiData = jsonData[0];
    if (aiData.output) {
      aiData = JSON.parse(aiData.output);
    }
  } else if (jsonData.output) {
    aiData = JSON.parse(jsonData.output);
  } else {
    aiData = jsonData;
  }
} 
catch (err) {
  return { json: buildErrorResult(err.message) };
}

let companyData = buildBaseResult(aiData);
let { errors, status } = validateCompanyData(companyData);

let result = buildResult(companyData, errors, status);

return {
  json: result
};

function buildErrorResult(errorMessage) {
  return {
    shortSummary: 'Error parsing data',
    detailedSummary: 'Error parsing data',
    lastUpdate: new Date().toISOString(),
    pubDate: 'Unknown',
    revenue: 'Error parsing data',
    errorMessage: errorMessage,
    isValid: "invalidData",
    errors: ["ERROR PARSING DATA"]
  };
}

function buildBaseResult(aiData) {
  return {
    shortSummary: aiData.shortSummary || 'Unknown',
    detailedSummary: aiData.detailedSummary || 'Unknown',
    pubDate: aiData.pubDate || 'Unknown',
    revenue: aiData.revenue || 'Unknown',
    lastUpdate: new Date().toISOString() 
  }
}

function buildResult(companyData, errors, status) {
  return {
    ...companyData,
    errors: errors,
    isValid: status
  }
}

function validateCompanyData(companyData) {
  let errors = [];
  let status;

  if (companyData.shortSummary === "Unknown") errors.push('INVALID shortSummary');
  if (companyData.detailedSummary === "Unknown") errors.push('INVALID detailedSummary');
  if (companyData.pubDate === 'Unknown') errors.push('INVALID pubDate');
  if (companyData.revenue === "Unknown") errors.push('INVALID revenue')
  if (
    companyData.shortSummary === "Unknown" ||
    companyData.detailedSummary === "Unknown"
  ) {
    status = "invalidData"
  } else {
    status = "validData";
  }

  return { errors, status };
}
